const Q_CHEMISTRY_2021_MODEL_II=[{"id": "objective>Chemistry>2021-Model-II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 0.20 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> was evaporated to yield 5.0g of solid NaOH. Calculate the volume of NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> used.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">600cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">625cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1600cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Molar concentration = 0.20 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> mass, m = 5.0g <br/> volume, V = ? <br/> Molar mass = 40g/mol <br/> Recall:  <br/> mass concentration = molar mass × molar concentration <br/> mass concentration = 0.20 × 40 = 8g/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> ∴ <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mass</td><td style=\"text-align:center;\">concentration</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />volume</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />V</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.625dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div> <br/> N.B: 0.625dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 625cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2021-Model-II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of 800cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a gas Q at s.t.p is 1.0g. What is the molar mass of Q?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18.0gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">22.4gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">28.0gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">36.0gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: 1g of the gas occupies 800cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> x of the gas occupies 22,400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at s.t.p <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">800<hr size=\"1\" />22,400</td></tr></table></div> <br/> 800x = 22,400 <br/> x = 28g <br/> N,B: 1 mole of the gas occupies 22,400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at s.t.p <br/> ∴ mass of one mole = 28g = molar mass </div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>2021-Model-II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A compound U melts at 82°C and boils at 113°C. If U was found to be insoluble in water, a mixture of U in water could best be separated by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chromatography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filtration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of separating funnel</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The compound U is insoluble in water and thus, when mixed with water, it will not dissolve. This means that the particles of U will be suspended in the water. Filtration is a method used to separate undissolved solids from a liquid, which is exactly what is needed in this case. Therefore, the mixture of U and water could best be separated by filtration.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2021-Model-II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zinc oxide is said to be amphoteric because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">forms an acid salt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is an insoluble base </div>", "<div style=\"font-family:Cambria;font-size:17px;\">forms a double salt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reacts with a base or an acid</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An amphoteric oxide is an oxide that has both acidic and basic property, i.e it can function both as an acid and as a base.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2021-Model-II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases is used to retard the vapourization of the filament in a light bulb?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Argon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Helium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Argon is used in light bulbs to prevent the tungsten filament from vaporizing too quickly. Argon is a noble gas, which means it is chemically inert and does not react with the filament even at high temperatures. This helps to prolong the life of the bulb.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2021-Model-II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxide from electric power station is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Carbon(IV)oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper(II)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen(IV)oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur(IV)oxide </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxide from electric power stations is Sulphur(IV)oxide. This is because the burning of fossil fuels, such as coal and oil, in power stations releases Sulphur(IV)oxide into the atmosphere.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2021-Model-II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The production of biogas from the fermentation of waste materials is an example of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">combustion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incineration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refining </div>", "<div style=\"font-family:Cambria;font-size:17px;\">recycling </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The production of biogas from the fermentation of waste materials is an example of recycling. This is because the waste materials are being reused to produce a useful product (biogas), rather than being discarded.</div>", "topic": "ENERGY CHANGES : SPONTANEITY OF REACTIONS"}, {"id": "objective>Chemistry>2021-Model-II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The purity of a solid sample can best be determined by its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">melting point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conductivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solubility</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The purity of a solid can best be described by its melting point. A pure solid has a sharp melting point.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : BIOLING AND MELTING POINTS"}, {"id": "objective>Chemistry>2021-Model-II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> They are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">allotropes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dimers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">polymers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">geometric isomers </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two compounds given are cis-trans isomers or geometric isomers.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2021-Model-II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When an atom gains an electron, it becomes </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chemically inactive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">negatively charged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a cation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When an atom gains an electron, it becomes negatively charged. This is because electrons carry a negative charge. When an atom gains an electron, it has more electrons than protons, resulting in a negative charge.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2021-Model-II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following denotes an alpha particle.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span>e</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Be</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An alpha particle is denoted by <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He. It consists of 2 protons and 2 neutrons, hence the mass number is 4 and the atomic number is 2. The atomic number is represented by the subscript and the mass number by the superscript.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2021-Model-II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During water treatment for town water supply water is passed through layers of sand beds in order to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soften the water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filter the water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decolorize the water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">destroy germs in the water </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During water treatment for town water supply, water is passed through layers of sand beds in order to filter the water. This process is known as sand filtration and it helps in removing suspended particles from the water.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2021-Model-II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following exhibits resonance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Benzene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Butane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pentene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Octane </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Benzene exhibits resonance. The resonance structure of benzene was proposed by August Kekule' <br/> <img src=\"2021-Model-II/chem9.png\" style=\"position:relative;max-width:100%;\"/> <br/> Resonance structure of Benzene. </div>", "topic": "ORGANIC COMPOUNDS : AROMATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2021-Model-II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a disaccharide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fructose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cellulose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sucrose </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sucrose is a disaccharide. A disaccharide is a sugar (a carbohydrate) composed of two monosaccharides. Sucrose is composed of the monosaccharides glucose and fructose.</div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}, {"id": "objective>Chemistry>2021-Model-II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of hydrogen will be produced if 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of ammonia is completely decomposed at constant temperature and pressure? <br/> The equation for the reaction is: <br/> 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> → N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">300cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given the equation for the reaction: <br/> 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> → N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> 2 &nbsp &nbsp &nbsp  &nbsp  &nbsp &nbsp &nbsp &nbsp &nbsp  1 &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp  &nbsp 3 <br/> 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> &nbsp 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> &nbsp  150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> From the analysis above, using Gay Lussac's law of combining volume, 150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of hydrogen will be produced. <br/> </div>", "topic": "CHEMICAL COMBINATION : AVOGADRO'S LAW"}, {"id": "objective>Chemistry>2021-Model-II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas given off when NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl is heated with an alkali is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When ammonium chloride (NH4Cl) is heated with an alkali, ammonia gas (NH3) is produced.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2021-Model-II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following increases in mass when heated in air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sodium chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Iodine crystal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium ribbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper (II) oxide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium ribbon will react with oxygen (in air) to yield magnesium oxide. Other options contain substances which will not react in air. <br/> 2Mg + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2MgO</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2021-Model-II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the expression for the equilibrium constant (K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span>) for the following reaction? <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌ 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(NO)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)+(O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(2NO)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)(O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)+(O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)<hr size=\"1\" />2(NO)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(NO)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)(O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)</td></tr></table></div></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium constant expression for the reaction N2(g) + O2(g) ⇌ 2NO(g) is given by Kc = [NO]^2 / ([N2][O2]).</div>", "topic": "CHEMICAL EQUILIBRIA : DYNAMIC EQUILIBRIUM"}, {"id": "objective>Chemistry>2021-Model-II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A suitable reagent for distinguishing between ethanoic acid and ethanol is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bromine water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fehling's solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium hydrogentrioxocarbonate (IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ammoniacal silver trioxonitrate (V)</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanoic acid reacts with sodium hydrogen trioxocarbonate (iv) to yield carbon (IV) oxide while ethanol will not give any reaction.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2021-Model-II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC name for CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHCLCHCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2, 4 - dimethyl - 3 - chlorohexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3, 5 - dimethyl - 4 - chlorohexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 - chloro - 3, 5 - dimethylhexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 - chloro - 2, 4 - dimethylhexane</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC name for the given compound is determined by identifying the longest carbon chain and numbering it in such a way that the substituents (in this case, the chlorine atom and the methyl groups) get the lowest possible numbers. The longest carbon chain here is six carbons long (hexane), and numbering from the left gives the chlorine atom the number 4 and the methyl groups the numbers 3 and 5. Therefore, the correct IUPAC name is 3, 5 - dimethyl - 4 - chlorohexane.</div>", "topic": "ELECTROLYSIS : FACTORS AFFECTING DISCHARGE OF IONS AT THE ELECTRODES"}, {"id": "objective>Chemistry>2021-Model-II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the structure below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> What is the IUPAC name of the compound with this structure? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3-methylbutane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-methylpentane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylbutane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylpropane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <img src=\"2021-Model-II/chem10.png\" style=\"position:relative;max-width:100%;\"/> <br/> - The longest continuous carbon chain has four (4) carbon atoms. The root name is BUTANE <br/>  <br/> - It has methyl (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) on the second carbon. <br/>  <br/> The name of the compound is 2 - methylbutane.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2021-Model-II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following elements would produce coloured ions aqueous solutions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Iron (Fe) is known to produce coloured ions in aqueous solutions. This is due to the d-d transitions of the d-electrons. When light passes through these solutions, certain wavelengths are absorbed by these transitions. The remaining light gives the solution its characteristic colour.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2021-Model-II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If two metallic ions of the same concentration migrate to the cathode (graphite), the one that will be preferentially discharged is the one that has the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">smaller mass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower electrical charge </div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater stability in solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stronger tendency to accept electrons </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If two metallic ions of the same concentration migrate to the cathode (graphite), the one that will be preferentially discharged is the one that has the tendency to accept electrons, i.e low reducing potential.</div>", "topic": "ELECTROLYSIS : FACTORS AFFECTING DISCHARGE OF IONS AT THE ELECTRODES"}, {"id": "objective>Chemistry>2021-Model-II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of hydrogen diffuses through a porous pot in 1.0 second, how long will it take the same volume of oxygen to diffuse through the same pot under the same conditions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.25s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.0s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.0s</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span> =100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span> = 1.0 sec <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">O</span>= 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">O</span> = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">O</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">MM<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">O</span><hr size=\"1\" />MM<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> 100/1 = t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">O</span>/100 =√32/2 <br/>  <br/> t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">oxygen</span>=&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">16&nbsp;</span> <br/> t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">oxygen</span> = 4 <br/> </div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2021-Model-II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following processes involves neutralization?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hardening of oils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Souring of milk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Charring of sugar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liming of soil</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Neutralization is a chemical reaction in which an acid and a base react to form a salt and water. Liming of soil is a process that involves the neutralization of acidic soil by adding lime (calcium carbonate), which is a base.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2021-Model-II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following involves a beta particle emission?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">234</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">230</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">90</span>Th</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">238</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">80</span>Hg → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">238</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">81</span>Ti</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">238</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">234</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>Th</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">12</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">238</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">80</span>Hg → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">238</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">81</span> + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span>e <br/> N.B: <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span>e is beta particle</div>", "topic": "NUCLEAR CHEMISTRY : RADIOACTIVITY"}, {"id": "objective>Chemistry>2021-Model-II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A given fuel has an octane number of 100. This means that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the knocking tendency of the fuel is low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the fuel is a mixture of several hydrocarbons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a large amount of alkanes is present in the fuel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the fuel needs to be cracked before use</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The octane number of a fuel is a measure of its knocking tendency in a spark-ignition internal combustion engine. A fuel with an octane number of 100 has a low knocking tendency, meaning it can withstand higher compression before igniting. This makes the engine run more smoothly and efficiently.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2021-Model-II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Wine containing 8% to 17% ethanol can be converted to gin containing about 40% ethanol by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fermentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidation </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Distillation is a process used to separate components of a mixture based on differences in their boiling points. In the case of converting wine to gin, the ethanol in the wine is separated from the other components by heating the mixture to the boiling point of ethanol, which is lower than the boiling points of the other components. The ethanol vapor is then condensed and collected, resulting in a higher concentration of ethanol.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2021-Model-II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the equilibrium reaction below: <br/> 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌ 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> [ΔH = -x KJ/mol] <br/> The amount of sulphur (VI) oxide produced will increase if </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the pressure is decreased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">more heat is applied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the temperature is reduced </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a catalyst is added</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the reaction is exothermic, a decrease in temperature will favor the forward reaction, hence, the production of sulphur (vi) oxide will increase.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2021-Model-II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about an exothermic reaction is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The product has less heat content than the reactants.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The system absorbs heat from the surroundings.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The activation energy is high.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The enthalpy change is positive.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A reaction is said to be exothermic if it releases heat to the surroundings. This implies that the heat content of the products is less than that of the reactants.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2021-Model-II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The complex salt formed when aluminium dissolves in sodium hydroxide solution is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>Al(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Al(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaAl(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Al(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When aluminium is treated with dilute sodium hydroxide it forms a salt called sodium tetrahydroxoaluminate and hydrogen gas. <br/> Al + NaOH → NaAl(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2021-Model-II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a waste product in the Solvay process for the manufacture of sodium trioxocarbonate (IV)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ammonium chloride </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Limestone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Calcium chloride </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principal by product of Solvay process is calcium chloride (CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>).</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2021-Model-II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water gas is a mixture of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO and N<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water gas is a mixture of carbon monoxide and hydrogen.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2021-Model-II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following measures is not suitable for controlling water pollution?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Treating industrial effluent and domestic sewage before discharge into water.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Controlling the use of agrochemicals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Recycling agricultural and industrial wastes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Burning industrial and agricultural wastes before discharge into waterways</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Burning industrial and agricultural waste before discharge into waterways is not suitable for controlling water pollution rather it will contribute more to water pollution.</div>", "topic": "ENVIRONMENTAL POLLUTION : WATER POLLUTION"}, {"id": "objective>Chemistry>2021-Model-II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pollutants is biodegradeable?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Domestic sewage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metal scraps </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plastic foil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radioactive waste</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Biodegradable pollutants are those that can be broken down by microorganisms into simpler, non-toxic substances. Domestic sewage is biodegradable as it contains organic matter that can be decomposed by bacteria. The other options are non-biodegradable pollutants.</div>", "topic": "ENVIRONMENTAL POLLUTION : SOURCES AND EFFECTS OF POLLUTANTS"}, {"id": "objective>Chemistry>2021-Model-II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What amount of electricity is required to deposit one mole of aluminium from a solution of AlCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">One Faraday</div>", "<div style=\"font-family:Cambria;font-size:17px;\">One ampere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Three Faradays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Three amperes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">AlCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 3Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> <br/> At cathode:  <br/> Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> +  3e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Al <br/> 3 mole of electrons corresponds 3 F charge <br/> So, required charge =3 F</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2021-Model-II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following acids forms normal salts only?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tetraoxosulphate (VI) acid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tetraoxosulphate (V) acid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trioxonitrate (V) acid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trioxosulphate (IV) acid </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Only monobasic acids form normal salts only. Trioxonitrate(V) acid, HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is a monobasic salt, hence, it will form only a normal salt.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2021-Model-II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following salts is insoluble in water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">AgCl</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">AgCl (Silver chloride) is insoluble in water. Most chloride salts are soluble, but AgCl is a notable exception. It is a white crystalline solid which readily absorbs moisture to form a grayish-white powder.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2021-Model-II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Salts that contain water of crystallization are said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">anhydrous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deliquescent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efflorescent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrated </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrated salts are salts that contains water of crystalization. <br/> Note: Efflorescence is the loss of part or all of a salt's water of crystalization when exposed to the atmosphere to form a lower hydrate or the anhydrous salt.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2021-Model-II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The product formed when concentrated sodium chloride solution is electrolysed using carbon electrodes is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chloride water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrochloric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium hydroxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium oxochlorate (I)</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When concentrated sodium chloride solution (brine) is electrolyzed using carbon electrodes, the products formed are chlorine gas, hydrogen gas, and sodium hydroxide.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}];
